// Generate test URLs
return [
  { json: { testName: 'Sweepstakes Fanatics', url: 'https://sweepstakesfanatics.com/home-depot-2026-march-madness-sweepstakes/' } },
  { json: { testName: 'Hip2Save', url: 'https://hip2save.com/deals/clear-promo-code/' } },
  { json: { testName: 'Contestgirl', url: 'https://www.contestgirl.com/contests/contests.pl?ar=na&b=nb&c=us&f=s&s=_&sort=p' } }
];

// Analyze what the HTTP Request node returned
const results = [];
for (const item of $input.all()) {
  const data = item.json.data || '';
  const testName = item.json.testName || 'Unknown';
  const isString = typeof data === 'string';
  const length = isString ? data.length : 0;
  const hasCloudflare = isString && data.includes('Just a moment');
  const has500 = isString && data.includes('500 Server Error');
  const isError = !!item.json.error;

  // Source-specific checks
  let hasContent = false;
  if (testName === 'Sweepstakes Fanatics') {
    hasContent = isString && data.includes('entry-content');
  } else if (testName === 'Hip2Save') {
    hasContent = isString && data.includes('entry-content');
  } else if (testName === 'Contestgirl') {
    hasContent = isString && data.includes('class="padded"');
  }

  results.push({ json: {
    test: testName,
    status: isError ? 'ERROR' : hasCloudflare ? 'CLOUDFLARE_BLOCKED' : has500 ? 'SERVER_ERROR' : hasContent ? 'SUCCESS' : length > 0 ? 'GOT_HTML_BUT_NO_CONTENT' : 'EMPTY',
    html_length: length,
    cloudflare_blocked: hasCloudflare,
    server_error: has500,
    has_expected_content: hasContent,
    error: item.json.error || '',
    first_200_chars: isString ? data.substring(0, 200) : '',
  }});
}
return results;
